const values = $json.values || [];

if (!values.length) {
  return [];
}

const headers = values[0].map(header => String(header || '').trim());
const rows = values.slice(1);

function get(row, headerName) {
  const index = headers.indexOf(headerName);
  if (index === -1) return '';
  return row[index] || '';
}

function clean(value) {
  return String(value || '').trim();
}

function normalizeStatus(value) {
  return clean(value).toLowerCase();
}

function normalizePackage(value) {
  const raw = clean(value);

  if (!raw) {
    return null;
  }

  const map = {
    malibu: 'Malibu',
    uluwatu: 'Uluwatu',
    waimea: 'Waimea',
    custom: 'Custom'
  };

  return map[raw.toLowerCase()] || raw;
}

function parseBeds(value) {
  return String(value || '')
    .split(',')
    .map(part => part.trim().toUpperCase())
    .filter(Boolean);
}

function escapeAirtableString(value) {
  return String(value || '')
    .replace(/\\/g, '\\\\')
    .replace(/"/g, '\\"');
}

function buildBedFormula(bedIds) {
  if (!bedIds.length) {
    return '';
  }

  if (bedIds.length === 1) {
    return `{Bed ID}="${escapeAirtableString(bedIds[0])}"`;
  }

  return `OR(${bedIds.map(id => `{Bed ID}="${escapeAirtableString(id)}"`).join(',')})`;
}

function actionFromSyncStatus(syncStatus) {
  const normalized = normalizeStatus(syncStatus);

  if (normalized === 'delete ready' || normalized === 'delete processing') {
    return 'delete';
  }

  if (normalized === 'update ready' || normalized === 'update processing') {
    return 'update';
  }

  if (normalized === 'ready' || normalized === 'processing') {
    return 'create';
  }

  return '';
}

function buildItem(row, rowNumber, action) {
  const bedIds = parseBeds(get(row, 'Room / Bed'));

  return {
    action,
    manual_entry_id: clean(get(row, 'Manual Entry ID')),
    row_number: rowNumber,
    created_at: clean(get(row, 'Created At')),
    created_by: clean(get(row, 'Created By')),
    guest_name: clean(get(row, 'Guest Name')),
    package: normalizePackage(get(row, 'Package')),
    deposit_paid: clean(get(row, 'Deposit Paid')),
    phone: clean(get(row, 'Phone')),
    email: clean(get(row, 'Email')),
    check_in: clean(get(row, 'Check In')).slice(0, 10),
    check_out: clean(get(row, 'Check Out')).slice(0, 10),
    guest_count: Number(get(row, 'Guest Count') || 1),
    room_bed: clean(get(row, 'Room / Bed')),
    bed_ids: bedIds,
    bed_filter_formula: buildBedFormula(bedIds),
    status: clean(get(row, 'Status')) || (action === 'delete' ? 'Cancelled' : 'Confirmed'),
    payment_status: clean(get(row, 'Payment Status')) || 'waiting_payment',
    notes: clean(get(row, 'Notes')),
    sync_status: clean(get(row, 'Sync Status')),
    airtable_booking_record_id: clean(get(row, 'Airtable Booking ID')),
    error: clean(get(row, 'Error'))
  };
}

// Priority order matters.
// This also lets reruns resume stuck processing rows.
const priority = [
  'delete processing',
  'delete ready',
  'update processing',
  'update ready',
  'processing',
  'ready'
];

let selected = null;

for (const wantedStatus of priority) {
  for (let i = 0; i < rows.length; i++) {
    const row = rows[i];
    const syncStatus = normalizeStatus(get(row, 'Sync Status'));

    if (syncStatus === wantedStatus) {
      const action = actionFromSyncStatus(syncStatus);
      selected = buildItem(row, i + 2, action);
      break;
    }
  }

  if (selected) {
    break;
  }
}

if (!selected) {
  return [];
}

if (!selected.manual_entry_id) {
  throw new Error(`Manual Entry ID missing on row ${selected.row_number}`);
}

if (!selected.guest_name && selected.action !== 'delete') {
  throw new Error(`Guest Name missing on row ${selected.row_number}`);
}

if (!selected.check_in || !selected.check_out) {
  throw new Error(`Check In / Check Out missing on row ${selected.row_number}`);
}

if (selected.action === 'create' && !selected.bed_ids.length) {
  throw new Error(`Room / Bed missing on row ${selected.row_number}`);
}

if ((selected.action === 'update' || selected.action === 'delete') && !selected.airtable_booking_record_id) {
  throw new Error(`Airtable Booking ID missing on row ${selected.row_number}`);
}

if (
  (selected.action === 'update' || selected.action === 'delete') &&
  !selected.airtable_booking_record_id.startsWith('rec')
) {
  throw new Error(
    `Airtable Booking ID on row ${selected.row_number} does not look like an Airtable record ID: ${selected.airtable_booking_record_id}`
  );
}

return [
  {
    json: selected
  }
];

const manual = $('Code - Pick Next Manual Queue Item').first().json;
const bedItems = $input.all();

function getFields(item) {
  return item.json.fields || item.json;
}

function getRecordId(item) {
  return item.json.id || item.json.record_id || item.json.Record_ID || '';
}

const foundBeds = bedItems.map(item => {
  const fields = getFields(item);

  return {
    record_id: getRecordId(item),
    bed_id: String(fields['Bed ID'] || '').trim().toUpperCase(),
    room_id: Array.isArray(fields['Room ID']) ? fields['Room ID'][0] : fields['Room ID'],
    fields
  };
}).filter(bed => bed.record_id && bed.bed_id);

const foundByBedId = {};

for (const bed of foundBeds) {
  foundByBedId[bed.bed_id] = bed;
}

const missing = manual.bed_ids.filter(bedId => !foundByBedId[bedId]);

if (missing.length) {
  throw new Error(`Missing Airtable bed record(s): ${missing.join(', ')}`);
}

const orderedBeds = manual.bed_ids.map(bedId => foundByBedId[bedId]);

return [
  {
    json: {
      ...manual,
      beds: orderedBeds,
      bed_record_ids: orderedBeds.map(bed => bed.record_id)
    }
  }
];

const manual = $('Code - Validate Beds For Create').first().json;
const createdBooking = $('Create Airtable Booking - Queue').first().json;

const bookingRecordId =
  createdBooking.id ||
  createdBooking.record_id ||
  createdBooking['Record ID'] ||
  '';

if (!bookingRecordId) {
  throw new Error('Could not find created Airtable Booking record ID.');
}

const bookingDisplayId =
  createdBooking.fields?.['Booking ID'] ||
  createdBooking['Booking ID'] ||
  bookingRecordId;

const output = [];

for (const bed of manual.beds) {
  output.push({
    json: {
      manual_entry_id: manual.manual_entry_id,
      row_number: manual.row_number,
      booking_record_id: bookingRecordId,
      booking_id: bookingDisplayId,
      bed_record_id: bed.record_id,
      bed_id: bed.bed_id,
      check_in: manual.check_in,
      check_out: manual.check_out,
      guest_name: manual.guest_name,
      guest_count: manual.guest_count,
      package: manual.package,
      deposit_paid: manual.deposit_paid,
      status: manual.status,
      payment_status: manual.payment_status,
      notes: manual.notes
    }
  });
}

return output;

