const manual = $('Code - Pick Next Manual Queue Item').first().json;
const bookingBedItems = $input.all();

function getRecordId(item) {
  return item.json.id || item.json.record_id || item.json.Record_ID || '';
}

function getFields(item) {
  return item.json.fields || item.json;
}

function linkedIds(value) {
  if (!value) return [];

  if (Array.isArray(value)) {
    return value.map(v => String(v || '').trim()).filter(Boolean);
  }

  return [String(value || '').trim()].filter(Boolean);
}

const targetBookingRecordId = manual.airtable_booking_record_id;
const matches = [];

for (const item of bookingBedItems) {
  const fields = getFields(item);
  const recordId = getRecordId(item);

  const linkedBookingIds = [
    ...linkedIds(fields['Booking']),
    ...linkedIds(fields['Bookings'])
  ];

  if (recordId && linkedBookingIds.includes(targetBookingRecordId)) {
    matches.push({
      json: {
        manual_entry_id: manual.manual_entry_id,
        row_number: manual.row_number,
        airtable_booking_record_id: targetBookingRecordId,
        booking_bed_record_id: recordId,
        guest_name: manual.guest_name,
        check_in: manual.check_in,
        check_out: manual.check_out,
        no_booking_beds_found: false
      }
    });
  }
}

if (!matches.length) {
  return [
    {
      json: {
        manual_entry_id: manual.manual_entry_id,
        row_number: manual.row_number,
        airtable_booking_record_id: targetBookingRecordId,
        booking_bed_record_id: '',
        guest_name: manual.guest_name,
        check_in: manual.check_in,
        check_out: manual.check_out,
        no_booking_beds_found: true,
        message: 'No Booking Beds found for this booking. Will still mark Booking as Cancelled.'
      }
    }
  ];
}

return matches;

const manual = $('Code - Pick Next Manual Queue Item').first().json;

return [
